#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#define fp float

#define NUMBER_THREADS 32

#define EQUATIONS 91
#define PARAMETERS 18

#include "kernel_fin_2.cu"
#include "kernel_ecc_2.cu"
#include "kernel_cam_2.cu"
#include "kernel_2.cu"
#include "embedded_fehlberg_7_8_2.cu"
#include "solver_2.cu"

void read(char* filename, fp* input, int data_rows, int data_cols, int major);
long long get_time();

int work_2(int xmax, int workload){

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	long memory;
	int i;
	int pointer;

	fp* y;
	fp* d_y;
	long y_mem;

	fp* x;
	fp* d_x;
	long x_mem;

	fp* params;
	fp* d_params;
	int params_mem;

	fp* d_com;
	int com_mem;

	fp* d_err;
	int err_mem;

	fp* d_scale;
	int scale_mem;

	fp* d_yy;
	int yy_mem;

	fp* d_initvalu_temp;
	int initvalu_temp_mem;

	fp* d_finavalu_temp;
	int finavalu_temp_mem;

	int blocks_x;

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y_mem = workload * (xmax+1) * EQUATIONS * sizeof(fp);
	y= (fp *) malloc(y_mem);
	d_y = (fp *) malloc(y_mem);

	x_mem = workload * (xmax+1) * sizeof(fp);
	x= (fp *) malloc(x_mem);
	d_x = (fp *) malloc(x_mem);

	params_mem = workload * PARAMETERS * sizeof(fp);
	params= (fp *) malloc(params_mem);
	d_params = (fp *) malloc(params_mem);

	com_mem = workload * 3 * sizeof(fp);
	d_com = (fp *) malloc(com_mem);

	err_mem = workload * EQUATIONS * sizeof(fp);
	d_err = (fp *) malloc(err_mem);

	scale_mem = workload * EQUATIONS * sizeof(fp);
	d_scale = (fp *) malloc(scale_mem);

	yy_mem = workload * EQUATIONS * sizeof(fp);
	d_yy = (fp *) malloc(yy_mem);

	initvalu_temp_mem = workload * EQUATIONS * sizeof(fp);
	d_initvalu_temp = (fp *) malloc(initvalu_temp_mem);

	finavalu_temp_mem = workload * 13* EQUATIONS * sizeof(fp);
	d_finavalu_temp = (fp *) malloc(finavalu_temp_mem);

	time2 = get_time();

	for(i=0; i<workload; i++){
		pointer = i * (xmax+1) + 0;
		x[pointer] = 0;
	}
	for(i=0; i<workload; i++){
		d_x[i * (xmax+1) + 0] = 0;
	}

	for(i=0; i<workload; i++){
		pointer = i*((xmax+1)*EQUATIONS) + 0*(EQUATIONS);
		read("../../data/myocyte/y.txt",
					&y[pointer],
					91,
					1,
					0);
	}
	for(i=0; i<workload * (xmax+1) * EQUATIONS; i++){
		d_y[i] = y[i];
	}

	for(i=0; i<workload; i++){
		pointer = i*PARAMETERS;
		read("../../data/myocyte/params.txt",
					&params[pointer],
					18,
					1,
					0);
	}
	for(i=0; i<workload * PARAMETERS; i++){
		d_params[i] = params[i];
	}

	time3 = get_time();

#pragma omp parallel for
	for(i=0; i<workload; i++){
		solver_2(	workload,
						xmax,
						i,
						d_x,
						d_y,
						d_params,
						d_com,
						d_err,
						d_scale,
						d_yy,
						d_initvalu_temp,
						d_finavalu_temp);
	}

	time4 = get_time();

	for(i=0; i<workload * (xmax+1) * EQUATIONS; i++){
		y[i] = d_y[i];
	}
	for(i=0; i<workload * (xmax+1); i++){
		x[i] = d_x[i];
	}

	time5 = get_time();

	free(y);
	free(d_y);

	free(x);
	free(d_x);

	free(params);
	free(d_params);

	free(d_com);

	free(d_err);
	free(d_scale);
	free(d_yy);

	free(d_initvalu_temp);
	free(d_finavalu_temp);

	time6= get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n",															(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n",				(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES, COPY TO GPU MEMORY\n",		(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : RUN GPU KERNEL\n",															(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : COPY GPU DATA TO CPU MEMORY\n",								(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n",																(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n",																											(float) (time6-time0) / 1000000);

	return 0;

}
